// shared/service-registry.js
export function buildServiceRegistry(env) {
  // Flexible registry: any internal worker can bind to any other via a shared env.SERVICES mapping
  // In Wrangler, you can inject SERVICES as an object via vars, or just bind individually (USER, ORDER, SEARCH, ROUTER).
  const registry = env.SERVICES || {};
  return new Proxy(registry, {
    get(target, prop) {
      if (prop in target) return target[prop];
      if (prop in env) return env[prop];
      return undefined;
    },
  });
}


